void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;
  //MilkDrop3 Multiplicate Mode:
vUv = 1- abs( fract((vUv-.5)*1.5 * 0.5 ) * 2 - 1.0 );

ret = GetPixel(vUv);
//MilkDrop3 Solarize Mode:
